struct TwoSet {
	// priority_queue 比 multiset 更快
	priority_queue<int> l;
	priority_queue<int, vector<int>, greater<int>> r;
	int len = 0;
	void insert(int x) {
		len++;
		if (l.empty() or x <= l.top())l.push(x);
		else r.push(x);
		int mid = (len + 1) / 2;
		while (l.size() > mid) {
			r.push(l.top());
			l.pop();
		}
		while (l.size() < mid) {
			l.push(r.top());
			r.pop();
		}
	}
	int get() {
		if (len == 0)assert("cannot find");
		return l.top();
	}
};

struct TwoSet {
	multiset<int, greater<int>> l;
	multiset<int> r;
	int len = 0;
	void insert(int x) {
		len++;
		if (l.empty() or x <= *l.begin())l.insert(x);
		else r.insert(x);
		balance();
	}
	void erase(int x) {
		if (!l.count(x) and !r.count(x))assert("cannot find");
		len--;
		if (l.count(x))l.erase(l.find(x));
		else r.erase(r.find(x));
		balance();
	}
	void balance() {
		int mid = (len + 1) / 2;
		while (l.size() > mid) {
			r.insert(*l.begin());
			l.erase(l.begin());
		}
		while (l.size() < mid) {
			l.insert(*r.begin());
			r.erase(r.begin());
		}
	}
	int get() {
		if (len == 0)assert("cannot find");
		return *l.begin();
	}
};
